@import url('/assets/font/index.css');

:root {
	// 白色颜色
	--vh-white-color: #fff;
	// BoxShadow
	--vh-box-shadow: 0 3px 8px 6px #07111b0d;
	// Body 背景颜色
	--vh-body-bg: #F8F8F8;
	// Back Top 按钮位置
	--vh-back-top: calc((calc(100vw - 2rem) - min((100vw - 2rem), var(--vh-main-max-width))) / 2 + 1rem);
	// 字体颜色
	--vh-font-88: rgb(from var(--vh-font-color) r g b / 88%);
	--vh-font-66: rgb(from var(--vh-font-color) r g b / 66%);
	--vh-font-56: rgb(from var(--vh-font-color) r g b / 56%);
	--vh-font-28: rgb(from var(--vh-font-color) r g b / 28%);
	--vh-font-16: rgb(from var(--vh-font-color) r g b / 16%);
	--vh-font-6: rgb(from var(--vh-font-color) r g b / 6%);
	// 主题色
	--vh-main-color-88: rgb(from var(--vh-main-color) r g b / 88%);
	--vh-main-color-66: rgb(from var(--vh-main-color) r g b / 66%);
	--vh-main-color-56: rgb(from var(--vh-main-color) r g b / 56%);
	--vh-main-color-28: rgb(from var(--vh-main-color) r g b / 28%);
	--vh-main-color-16: rgb(from var(--vh-main-color) r g b / 16%);
	--vh-main-color-6: rgb(from var(--vh-main-color) r g b / 6%);

	// Default 
	--vh-default: #BEC4CC;
	--vh-default-hover: #BEC4CC18;
	// Info 
	--vh-info: #3253b4;
	--vh-info-hover: #3253b418;
	// Success
	--vh-success: #01C4B6;
	--vh-success-hover: #01C4B618;
	// Warning
	--vh-warning: #DD8636;
	--vh-warning-hover: #DD863618;
	// Error
	--vh-error: #DE3C3D;
	--vh-error-hover: #DE3C3D18;
	// Import
	--vh-import: #B984DF;
	--vh-import-hover: #B984DF18;
}

* {
	// IOS 点击阴影
	-webkit-tap-highlight-color: transparent;
	// 隐藏滚动条
	scrollbar-width: none;
	-ms-overflow-style: none;
	// 去除下划线
	text-decoration: none;
	// 消除边框
	outline: none;

	// 隐藏滚动条
	::-webkit-scrollbar {
		display: none;
	}
}

// 设置文本选中颜色
::selection,
::-webkit-selection {
	color: #fff;
	background: var(--vh-main-color-88);
}

html {
	word-wrap: break-word;
	overflow-wrap: break-word;
	font-size: 16px;
	font-weight: 400;

	&>body {
		position: relative;
		box-sizing: border-box;
		display: flex;
		flex-direction: column;
		width: 100vw;
		height: max-content;
		color: var(--vh-font-color);
		font-family: 'HarmonyOS Sans SC', serif;
		font-weight: 400;
		cursor: url('/assets/images/default.cur'), default;
		overflow-x: hidden;

		&::before {
			content: "";
			position: fixed;
			left: 0;
			top: 0;
			width: 100vw;
			height: 100vh;
			// background: #fff url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 32 32' width='8' height='8' fill='none' stroke='rgb(0 0 0 / 0.1)'%3e%3cpath d='M0 .5H31.5V32'/%3e%3c/svg%3e");
			background: #fff url('/assets/images/bg.png');
			opacity: 0.188;
			z-index: -1;
		}

		&>footer {
			box-sizing: border-box;
			width: 100%;
			height: max-content;
		}
	}
}

pre,
code {
	font-family: 'SF Mono' !important;
}

a {
	color: var(--vh-font-color);
}

img {
	user-select: none;
	-webkit-user-drag: none;
}

img[data-vh-lz-src] {
	transition: all 0.18s ease-in;

	&:not(.loaded) {
		filter: blur(0.88rem) brightness(1);
	}
}


// ===================================================================== Other 
// 悬浮背景 a 标签
.vh-hover {
	position: relative;
	transition: all 0.18s ease-in-out;

	&:hover,
	&.active {
		color: var(--vh-white-color) !important;

		&::before {
			transform: scale(1.2);
			opacity: 1;
		}
	}

	&::before {
		content: "";
		position: absolute;
		left: 0;
		top: 0;
		width: 100%;
		height: 100%;
		border-radius: .5rem;
		background-color: var(--vh-main-color-88);
		opacity: 0;
		z-index: -1;
		transition: all 0.18s ease-in-out;
	}
}

// 超出一行省略
.vh-ellipsis {
	overflow: hidden;
	text-overflow: ellipsis;
	display: -webkit-box;
	-webkit-box-orient: vertical;
	word-break: break-all; // 解决纯数字/字母换行问题

	// 单行省略（默认）
	&:not([class*="line-"]) {
		white-space: nowrap;
		display: block;
	}

	.line-clamp(@lines) {
		white-space: normal;
		-webkit-line-clamp: @lines;
	}

	// 动态生成行数类
	&.line-2 {
		.line-clamp(2)
	}

	&.line-3 {
		.line-clamp(3)
	}
}

@media screen and (max-width: 768px) {
	// 手机端 禁止选择
	user-select: none;
	-webkit-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
}

// 设置图片懒加载样式
.main-inner>.main-inner-content,
.avatar {
	img[data-vh-lz-src] {
		transition: all 0.18s ease-in;

		&:not(.loaded) {
			filter: blur(0.88rem) brightness(1);
		}
	}
}

// 首次加载效果
.vh-animation.vh-animation-init {
	opacity: 0;
	animation: 300ms vh-init-show;
	animation-fill-mode: forwards;
	transition: opacity 0.18s ease-in-out, transform 0.18s ease-in-out;
}

// swup 动画效果
html.swup-enabled,
html.is-changing {
	.vh-animation {
		&.vh-animation-init {
			transform: translateY(0);
			opacity: 1;
			animation: none;
		}
	}
}

html.is-animating {
	.vh-animation {
		&.vh-animation-init {
			transform: translateY(0.88rem);
			opacity: 0;
		}
	}
}

// 占位加载
.vh-space-loading {
	box-sizing: border-box;
	display: flex;
	align-items: center;
	justify-content: center;
	grid-column: span 3;
	width: 100%;
	height: 8.88rem;
	overflow: hidden;

	&>span {
		background-color: #000;
		position: relative;
		width: 5px;
		height: 5px;
		margin: 3px;
		border-radius: 5px;

		&:nth-of-type(1) {
			-webkit-animation: scale .8s ease infinite;
			animation: vh-loading-animation .8s ease infinite
		}

		&:nth-of-type(2) {
			-webkit-animation: scale .8s ease .2s infinite;
			animation: vh-loading-animation .8s ease .2s infinite
		}

		&:nth-of-type(3) {
			-webkit-animation: scale .8s ease .4s infinite;
			animation: vh-loading-animation .8s ease .4s infinite
		}

	}
}

// 谷歌广告模块
.vh-ad {
	position: relative;
	display: block;
	width: 100%;
	height: max-content;
	min-height: 5.88rem;
	overflow: hidden !important;
	z-index: 1;

	&.vh-article-ad {
		margin-bottom: 1rem;
		box-sizing: border-box;
		padding: 0.75rem;
		border-radius: 0.5rem;
		background-color: var(--vh-white-color);
		box-shadow: var(--vh-box-shadow);
		overflow: hidden;

		&::before {
			top: 50%;
		}
	}

	&::before {
		position: absolute;
		left: 50%;
		top: 30%;
		transform: translate(-50%, -50%);
		content: '广告加载中...';
		color: #e3e4e6;
		z-index: -1;
	}
}



@keyframes vh-init-show {
	0% {
		transform: translateY(2rem);
		opacity: 0;
	}

	100% {
		transform: translateY(0);
		opacity: 1;
	}
}

@keyframes vh-loading-animation {
	50% {
		height: 25px
	}

	0% {
		height: 5px
	}
}

@-webkit-keyframes vh-init-show {
	0% {
		transform: translateY(2rem);
		opacity: 0;
	}

	100% {
		transform: translateY(0);
		opacity: 1;
	}
}

@-webkit-keyframes vh-loading-animation {
	50% {
		height: 25px
	}

	0% {
		height: 5px
	}
}


// 动画效果
@keyframes talking-tag-active {
	0% {
		transform: translateX(0);
	}

	25% {
		transform: translateX(-1.66px);
	}

	50% {
		transform: translateX(1.66px);
	}

	75% {
		transform: translateX(-1.66px);
	}

	100% {
		transform: translateX(0);
	}
}

@-webkit-keyframes talking-tag-active {
	0% {
		transform: translateX(0);
	}

	25% {
		transform: translateX(-1.66px);
	}

	50% {
		transform: translateX(1.66px);
	}

	75% {
		transform: translateX(-1.66px);
	}

	100% {
		transform: translateX(0);
	}
}

arguments.content:
@import url('/assets/font/index.css');

// 像素风格变量
:root {
	// 像素风格配色
	--vh-pixel-bg: #2d3436;
	--vh-pixel-text: #636e72;
	--vh-pixel-accent: #00cec9;
	--vh-pixel-secondary: #fd79a8;
	--vh-pixel-border: #b2bec3;
	--vh-pixel-shadow: #00000040;

	// 像素字体
	--vh-pixel-font: 'Press Start 2P', 'VT323', monospace;

	// 边框粗细
	--vh-pixel-border-thick: 4px;
	--vh-pixel-border-thin: 2px;

	// 阴影偏移
	--vh-pixel-shadow-offset: 4px;

	// 圆角（像素风格使用小圆角或无圆角）
	--vh-pixel-radius: 0;
}

* {
	-webkit-tap-highlight-color: transparent;
	scrollbar-width: none;
	-ms-overflow-style: none;
	text-decoration: none;
	outline: none;

	::-webkit-scrollbar {
		display: none;
	}
}

::selection,
::-webkit-selection {
	color: #fff;
	background: var(--vh-pixel-accent);
}

html {
	word-wrap: break-word;
	overflow-wrap: break-word;
	font-size: 16px;
	font-weight: 400;

	&>body {
		position: relative;
		box-sizing: border-box;
		display: flex;
		flex-direction: column;
		width: 100vw;
		height: max-content;
		color: var(--vh-pixel-text);
		font-family: var(--vh-pixel-font);
		font-weight: 400;
		cursor: url('/assets/images/pixel.cur'), default;
		overflow-x: hidden;

		&::before {
			content: "";
			position: fixed;
			left: 0;
			top: 0;
			width: 100vw;
			height: 100vh;
			background: var(--vh-pixel-bg);
			background-image:
				linear-gradient(45deg, var(--vh-pixel-border) 25%, transparent 25%, transparent 75%, var(--vh-pixel-border) 75%, var(--vh-pixel-border)),
				linear-gradient(45deg, var(--vh-pixel-border) 25%, transparent 25%, transparent 75%, var(--vh-pixel-border) 75%, var(--vh-pixel-border));
			background-size: 20px 20px;
			background-position: 0 0, 10px 10px;
			opacity: 0.1;
			z-index: -1;
		}

		&>footer {
			box-sizing: border-box;
			width: 100%;
			height: max-content;
		}
	}
}

pre,
code {
	font-family: 'Press Start 2P', monospace !important;
}

a {
	color: var(--vh-pixel-accent);
	text-decoration: none;
	position: relative;

	&::after {
		content: '';
		position: absolute;
		bottom: -2px;
		left: 0;
		width: 100%;
		height: var(--vh-pixel-border-thin);
		background-color: var(--vh-pixel-accent);
		transition: all 0.2s ease;
	}

	&:hover::after {
		height: var(--vh-pixel-border-thick);
		background-color: var(--vh-pixel-secondary);
	}
}

img {
	user-select: none;
	-webkit-user-drag: none;
	image-rendering: pixelated;
}

// 像素风格容器
.vh-pixel-box {
	position: relative;
	padding: 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-bg);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 var(--vh-pixel-shadow);
	transition: all 0.2s ease;
}

.vh-pixel-box:hover {
	transform: translate(-2px, -2px);
	box-shadow: calc(var(--vh-pixel-shadow-offset) + 2px) calc(var(--vh-pixel-shadow-offset) + 2px) 0 0 var(--vh-pixel-shadow);
}

// 像素风格按钮
.vh-pixel-btn {
	position: relative;
	display: inline-block;
	padding: 0.5rem 1.5rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.75rem;
	font-weight: bold;
	color: #fff;
	background-color: var(--vh-pixel-accent);
	border: var(--vh-pixel-border-thin) solid #fff;
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 #000;
	cursor: pointer;
	transition: all 0.1s ease;
	text-transform: uppercase;
}

.vh-pixel-btn:hover {
	background-color: var(--vh-pixel-secondary);
	transform: translate(-2px, -2px);
	box-shadow: calc(var(--vh-pixel-shadow-offset) + 2px) calc(var(--vh-pixel-shadow-offset) + 2px) 0 0 #000;
}

.vh-pixel-btn:active {
	transform: translate(2px, 2px);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 #000;
}

// 像素风格输入框
.vh-pixel-input {
	position: relative;
	width: 100%;
	padding: 0.75rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-text);
	background-color: var(--vh-pixel-bg);
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	box-shadow: inset 0 0 0 var(--vh-pixel-border-thin) #000;
	outline: none;
}

.vh-pixel-input:focus {
	border-color: var(--vh-pixel-accent);
}

// 像素风格滚动条
::-webkit-scrollbar {
	width: 16px;
	height: 16px;
}

::-webkit-scrollbar-track {
	background: var(--vh-pixel-bg);
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
}

::-webkit-scrollbar-thumb {
	background: var(--vh-pixel-accent);
	border: 2px solid var(--vh-pixel-bg);
}

::-webkit-scrollbar-thumb:hover {
	background: var(--vh-pixel-secondary);
}

// 像素风格标签
.vh-pixel-tag {
	display: inline-block;
	padding: 0.25rem 0.75rem;
	margin: 0.25rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.625rem;
	color: var(--vh-pixel-bg);
	background-color: var(--vh-pixel-accent);
	border: var(--vh-pixel-border-thin) solid #fff;
}

// 像素风格卡片
.vh-pixel-card {
	position: relative;
	padding: 1.5rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-bg);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 var(--vh-pixel-shadow);
	transition: all 0.2s ease;
}

.vh-pixel-card:hover {
	transform: translateY(-4px);
	box-shadow: calc(var(--vh-pixel-shadow-offset) + 4px) calc(var(--vh-pixel-shadow-offset) + 4px) 0 0 var(--vh-pixel-shadow);
}

// 像素风格加载动画
.vh-pixel-loading {
	position: relative;
	display: flex;
	justify-content: center;
	align-items: center;
	gap: 8px;
}

.vh-pixel-loading span {
	display: block;
	width: 12px;
	height: 12px;
	background-color: var(--vh-pixel-accent);
	animation: pixel-loading 1s ease-in-out infinite;
}

.vh-pixel-loading span:nth-child(2) {
	animation-delay: 0.2s;
}

.vh-pixel-loading span:nth-child(3) {
	animation-delay: 0.4s;
}

@keyframes pixel-loading {
	0%, 100% {
		transform: scale(1);
	}
	50% {
		transform: scale(0);
	}
}

// 像素风格头像
.vh-pixel-avatar {
	position: relative;
	width: 64px;
	height: 64px;
	border: var(--vh-pixel-border-thick) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-accent);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 #000;
	image-rendering: pixelated;
}

// 像素风格分割线
.vh-pixel-divider {
	width: 100%;
	height: var(--vh-pixel-border-thick);
	background: repeating-linear-gradient(
		45deg,
		var(--vh-pixel-border),
		var(--vh-pixel-border) 2px,
		transparent 2px,
		transparent 8px
	);
	border: none;
}

// 像素风格标题
.vh-pixel-title {
	font-family: var(--vh-pixel-font);
	font-size: 1.5rem;
	font-weight: bold;
	color: var(--vh-pixel-accent);
	text-transform: uppercase;
	letter-spacing: 2px;
	line-height: 1.5;
	margin-bottom: 1rem;
}

// 像素风格文本
.vh-pixel-text {
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	line-height: 1.6;
	color: var(--vh-pixel-text);
}

// 像素风格列表
.vh-pixel-list {
	list-style: none;
	padding: 0;
	margin: 0;
}

.vh-pixel-list li {
	position: relative;
	padding-left: 2rem;
	margin-bottom: 0.5rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-text);
}

.vh-pixel-list li::before {
	content: '►';
	position: absolute;
	left: 0;
	color: var(--vh-pixel-accent);
}

// 像素风格代码块
.vh-pixel-code {
	font-family: 'Press Start 2P', monospace;
	font-size: 0.75rem;
	padding: 0.5rem;
	background-color: #000;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	color: #0f0;
}

// 像素风格警告框
.vh-pixel-warning {
	padding: 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-secondary);
	background-color: rgba(253, 121, 168, 0.1);
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-secondary);
}

// 像素风格成功框
.vh-pixel-success {
	padding: 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-accent);
	background-color: rgba(0, 206, 201, 0.1);
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-accent);
}

// 像素风格图片容器
.vh-pixel-image {
	position: relative;
	overflow: hidden;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 var(--vh-pixel-shadow);
	image-rendering: pixelated;
}

.vh-pixel-image img {
	width: 100%;
	height: auto;
	image-rendering: pixelated;
	transition: transform 0.2s ease;
}

.vh-pixel-image:hover img {
	transform: scale(1.05);
}

// 像素风格表格
.vh-pixel-table {
	width: 100%;
	border-collapse: collapse;
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
}

.vh-pixel-table th,
.vh-pixel-table td {
	padding: 0.75rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
}

.vh-pixel-table th {
	background-color: var(--vh-pixel-accent);
	color: var(--vh-pixel-bg);
}

.vh-pixel-table tr:nth-child(even) {
	background-color: rgba(0, 206, 201, 0.1);
}

// 像素风格导航
.vh-pixel-nav {
	display: flex;
	gap: 1rem;
	flex-wrap: wrap;
}

.vh-pixel-nav a {
	font-family: var(--vh-pixel-font);
	font-size: 0.75rem;
	padding: 0.5rem 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-bg);
	color: var(--vh-pixel-text);
	text-decoration: none;
	transition: all 0.2s ease;
}

.vh-pixel-nav a:hover,
.vh-pixel-nav a.active {
	background-color: var(--vh-pixel-accent);
	color: var(--vh-pixel-bg);
	border-color: #fff;
}

// 像素风格响应式
@media screen and (max-width: 768px) {
	.vh-pixel-title {
		font-size: 1.25rem;
	}

	.vh-pixel-text {
		font-size: 0.8125rem;
	}

	.vh-pixel-btn {
		font-size: 0.6875rem;
		padding: 0.375rem 1rem;
	}

	.vh-pixel-card {
		padding: 1rem;
	}
}

// 动画效果
@keyframes pixel-fade-in {
	0% {
		opacity: 0;
		transform: translateY(10px);
	}
	100% {
		opacity: 1;
		transform: translateY(0);
	}
}

.vh-pixel-fade-in {
	animation: pixel-fade-in 0.3s ease-out;
}

@keyframes pixel-blink {
	0%, 100% {
		opacity: 1;
	}
	50% {
		opacity: 0.5;
	}
}

.vh-pixel-blink {
	animation: pixel-blink 1s ease-in-out infinite;
}

