arguments.content:
/* === 像素风博客 - 基础样式 === */
@import url('https://fonts.googleapis.com/css2?family=Press+Start+2P&family=VT323&display=swap');

:root {
  --vh-main-color: #41a6f6;
  --vh-font-color: #f4f4f4;
  --vh-aside-width: 320px;
  --vh-main-radius: 0px;
  --vh-main-max-width: 1458px;

  // 像素风扩展变量
  --pixel-bg: #1a1c2c;
  --pixel-card: #262b44;
  --pixel-border: #333c57;
  --pixel-primary: #41a6f6;
  --pixel-secondary: #f77622;
  --pixel-accent: #e43b44;
  --pixel-success: #38b764;
  --pixel-text: #f4f4f4;
  --pixel-text-dim: #94a0b2;
  --pixel-code-bg: #0d0f1a;
  --pixel-code-color: #33ff33;
  --pixel-shadow-color: #000;
  --pixel-border-width: 3px;
  --pixel-shadow-offset: 4px;
  --pixel-font-title: 'Press Start 2P', monospace;
  --pixel-font-body: 'VT323', monospace;
  --pixel-transition: 0.15s ease;

  --vh-white-color: var(--pixel-card);
  --vh-box-shadow: 4px 4px 0 0 var(--pixel-shadow-color);
  --vh-body-bg: var(--pixel-bg);
  --vh-font-88: rgb(from var(--vh-font-color) r g b / 88%);
  --vh-font-66: rgb(from var(--vh-font-color) r g b / 66%);
  --vh-font-56: rgb(from var(--vh-font-color) r g b / 56%);
  --vh-font-28: rgb(from var(--vh-font-color) r g b / 28%);
  --vh-font-16: rgb(from var(--vh-font-color) r g b / 16%);
  --vh-font-6: rgb(from var(--vh-font-color) r g b / 6%);
  --vh-main-color-88: rgb(from var(--vh-main-color) r g b / 88%);
  --vh-main-color-66: rgb(from var(--vh-main-color) r g b / 66%);
  --vh-main-color-56: rgb(from var(--vh-main-color) r g b / 56%);
  --vh-main-color-28: rgb(from var(--vh-main-color) r g b / 28%);
  --vh-main-color-16: rgb(from var(--vh-main-color) r g b / 16%);
  --vh-main-color-6: rgb(from var(--vh-main-color) r g b / 6%);
}

* {
  -webkit-tap-highlight-color: transparent;
  scrollbar-width: none;
  -ms-overflow-style: none;
  text-decoration: none;
  outline: none;
  &::-webkit-scrollbar { display: none; }
}

::selection, ::-webkit-selection {
  color: #fff;
  background: var(--pixel-primary);
}

html {
  word-wrap: break-word;
  overflow-wrap: break-word;
  font-size: 16px;
  &>body {
    position: relative;
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    width: 100vw;
    min-height: 100vh;
    color: var(--pixel-text);
    font-family: var(--pixel-font-body);
    font-size: 18px;
    font-weight: 400;
    background-color: var(--pixel-bg);
    overflow-x: hidden;
    &::before {
      content: "";
      position: fixed;
      left: 0; top: 0;
      width: 100vw; height: 100vh;
      background-image:
        repeating-linear-gradient(0deg, transparent, transparent 19px, rgba(255,255,255,0.02) 19px, rgba(255,255,255,0.02) 20px),
        repeating-linear-gradient(90deg, transparent, transparent 19px, rgba(255,255,255,0.02) 19px, rgba(255,255,255,0.02) 20px);
      z-index: -1;
      pointer-events: none;
    }
    &>footer {
      box-sizing: border-box;
      width: 100%;
    }
  }
}

a {
  color: var(--pixel-primary);
  transition: color var(--pixel-transition);
  &:hover { color: var(--pixel-secondary); }
}

img {
  user-select: none;
  -webkit-user-drag: none;
  image-rendering: pixelated;
}

pre, code {
  font-family: var(--pixel-font-title) !important;
}

// === 像素风格通用组件 ===

// 像素卡片
.pixel-card {
  background: var(--pixel-card);
  border: var(--pixel-border-width) solid var(--pixel-border);
  box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);
  transition: transform var(--pixel-transition), box-shadow var(--pixel-transition);
  &:hover {
    transform: translate(-2px, -2px);
    box-shadow: calc(var(--pixel-shadow-offset) + 2px) calc(var(--pixel-shadow-offset) + 2px) 0 0 var(--pixel-shadow-color);
  }
}

// 像素按钮
.pixel-btn {
  display: inline-block;
  padding: 8px 16px;
  font-family: var(--pixel-font-title);
  font-size: 10px;
  color: var(--pixel-text);
  background: var(--pixel-primary);
  border: var(--pixel-border-width) solid var(--pixel-border);
  box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);
  cursor: pointer;
  transition: all var(--pixel-transition);
  text-transform: uppercase;
  letter-spacing: 1px;
  &:hover {
    transform: translate(-2px, -2px);
    box-shadow: calc(var(--pixel-shadow-offset) + 2px) calc(var(--pixel-shadow-offset) + 2px) 0 0 var(--pixel-shadow-color);
    background: var(--pixel-secondary);
  }
  &:active {
    transform: translate(2px, 2px);
    box-shadow: 2px 2px 0 0 var(--pixel-shadow-color);
  }
}

// 像素标签
.pixel-tag {
  display: inline-block;
  padding: 2px 8px;
  font-family: var(--pixel-font-title);
  font-size: 8px;
  color: var(--pixel-bg);
  background: var(--pixel-primary);
  border: 2px solid var(--pixel-border);
  text-transform: uppercase;
  letter-spacing: 1px;
}

// 像素输入框
.pixel-input {
  width: 100%;
  padding: 10px;
  font-family: var(--pixel-font-body);
  font-size: 18px;
  color: var(--pixel-text);
  background: var(--pixel-code-bg);
  border: var(--pixel-border-width) solid var(--pixel-border);
  box-shadow: inset 3px 3px 0 0 var(--pixel-shadow-color);
  outline: none;
  &:focus {
    border-color: var(--pixel-primary);
  }
}

// 像素分割线
.pixel-divider {
  width: 100%;
  height: 3px;
  background: repeating-linear-gradient(90deg, var(--pixel-border) 0, var(--pixel-border) 8px, transparent 8px, transparent 16px);
  border: none;
  margin: 1.5rem 0;
}

// 悬浮背景 a 标签
.vh-hover {
  position: relative;
  transition: all var(--pixel-transition);
  &:hover, &.active {
    color: var(--pixel-text) !important;
    background: var(--pixel-primary);
  }
}

// 超出一行省略
.vh-ellipsis {
  overflow: hidden;
  text-overflow: ellipsis;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  word-break: break-all;
  &:not([class*="line-"]) {
    white-space: nowrap;
    display: block;
  }
  &.line-2 { -webkit-line-clamp: 2; white-space: normal; }
  &.line-3 { -webkit-line-clamp: 3; white-space: normal; }
}

// 加载动画
.vh-space-loading {
  box-sizing: border-box;
  display: flex;
  align-items: center;
  justify-content: center;
  grid-column: span 3;
  width: 100%;
  height: 120px;
  &>span {
    background-color: var(--pixel-primary);
    width: 12px;
    height: 12px;
    margin: 4px;
    animation: vh-loading-animation .8s ease infinite;
    &:nth-of-type(1) { animation-delay: 0s; }
    &:nth-of-type(2) { animation-delay: .2s; }
    &:nth-of-type(3) { animation-delay: .4s; }
  }
}

@keyframes vh-loading-animation {
  0% { transform: scale(1); }
  50% { transform: scale(0.3); }
  100% { transform: scale(1); }
}

// 首次加载动画
@keyframes vh-init-show {
  0% { transform: translateY(20px); opacity: 0; }
  100% { transform: translateY(0); opacity: 1; }
}

.vh-animation.vh-animation-init {
  opacity: 0;
  animation: 300ms vh-init-show;
  animation-fill-mode: forwards;
}

// 打字机光标
@keyframes blink-cursor {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

.typewriter-cursor {
  display: inline-block;
  width: 10px;
  height: 20px;
  background: var(--pixel-primary);
  margin-left: 4px;
  animation: blink-cursor 1s step-end infinite;
}

@media screen and (max-width: 768px) {
  :root {
    --vh-aside-width: 0px;
  }
}

* { margin: 0; padding: 0; box-sizing: border-box; }
html, body, div, span, applet, object, iframe, h1, h2, h3, h4, h5, h6, p, blockquote, pre, a, abbr, address, big, cite, code, del, dfn, em, img, ins, kbd, q, s, samp, small, strike, strong, sub, sup, tt, var, b, u, i, center, dl, dt, dd, ol, ul, li, fieldset, form, label, legend, table, caption, tbody, tfoot, thead, tr, th, td, article, aside, canvas, details, embed, figure, figcaption, footer, header, hgroup, menu, nav, output, ruby, section, summary, time, mark, audio, video { border: 0; font-size: 100%; font: inherit; vertical-align: baseline; }
article, aside, details, figcaption, figure, footer, header, hgroup, menu, nav, section { display: block; }
body { line-height: 1; }
ol, ul { list-style: none; }
blockquote, q { quotes: none; }
blockquote:before, blockquote:after, q:before, q:after { content: ''; content: none; }
table { border-collapse: collapse; border-spacing: 0; }

/* === 文章详情页样式 === */
.article-detail {
  .article-header {
    margin-bottom: 2rem;
    padding-bottom: 1.5rem;
    border-bottom: var(--pixel-border-width) dashed var(--pixel-border);

    .article-title {
      font-family: var(--pixel-font-title);
      font-size: 20px;
      color: var(--pixel-primary);
      line-height: 1.6;
      margin-bottom: 1rem;
      word-break: break-word;
    }

    .article-meta {
      display: flex;
      flex-wrap: wrap;
      gap: 1rem;
      font-family: var(--pixel-font-title);
      font-size: 9px;
      color: var(--pixel-text-dim);

      span {
        display: inline-flex;
        align-items: center;
        gap: 4px;
      }
    }

    .article-tags {
      display: flex;
      flex-wrap: wrap;
      gap: 0.5rem;
      margin-top: 1rem;
    }
  }

  .article-content {
    font-family: var(--pixel-font-body);
    font-size: 20px;
    line-height: 1.8;
    color: var(--pixel-text);
    word-break: break-word;

    h1, h2, h3, h4, h5, h6 {
      font-family: var(--pixel-font-title);
      color: var(--pixel-primary);
      margin: 2rem 0 1rem;
      line-height: 1.4;
    }
    h1 { font-size: 18px; }
    h2 {
      font-size: 14px;
      padding-bottom: 0.5rem;
      border-bottom: var(--pixel-border-width) solid var(--pixel-border);
    }
    h3 { font-size: 12px; }
    h4 { font-size: 11px; }

    p { margin: 1rem 0; }

    a {
      color: var(--pixel-primary);
      border-bottom: 2px solid var(--pixel-primary);
      &:hover {
        color: var(--pixel-secondary);
        border-color: var(--pixel-secondary);
      }
    }

    img {
      max-width: 100%;
      border: var(--pixel-border-width) solid var(--pixel-border);
      box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);
      image-rendering: pixelated;
    }

    blockquote {
      padding: 1rem 1.5rem;
      margin: 1.5rem 0;
      background: rgba(65, 166, 246, 0.1);
      border-left: 4px solid var(--pixel-primary);
      border-top: 2px solid var(--pixel-border);
      border-bottom: 2px solid var(--pixel-border);
      border-right: 2px solid var(--pixel-border);
      color: var(--pixel-text-dim);
    }

    code {
      font-family: var(--pixel-font-title) !important;
      font-size: 10px;
      padding: 2px 6px;
      background: var(--pixel-code-bg);
      border: 2px solid var(--pixel-border);
      color: var(--pixel-code-color);
    }

    pre {
      padding: 1rem;
      margin: 1.5rem 0;
      background: var(--pixel-code-bg) !important;
      border: var(--pixel-border-width) solid var(--pixel-border);
      box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);
      overflow-x: auto;
      code {
        padding: 0;
        background: none;
        border: none;
        font-size: 9px;
        color: var(--pixel-code-color);
      }
    }

    table {
      width: 100%;
      border: var(--pixel-border-width) solid var(--pixel-border);
      margin: 1.5rem 0;
      th, td {
        padding: 10px;
        border: 2px solid var(--pixel-border);
        font-family: var(--pixel-font-body);
        font-size: 18px;
      }
      th {
        background: var(--pixel-primary);
        color: var(--pixel-bg);
        font-family: var(--pixel-font-title);
        font-size: 9px;
      }
      tr:nth-child(even) {
        background: rgba(65, 166, 246, 0.05);
      }
    }

    ul, ol {
      padding-left: 2rem;
      margin: 1rem 0;
      li {
        margin: 0.5rem 0;
        &::marker {
          font-family: var(--pixel-font-title);
          font-size: 10px;
        }
      }
    }

    hr {
      border: none;
      height: 3px;
      background: repeating-linear-gradient(90deg, var(--pixel-border) 0, var(--pixel-border) 8px, transparent 8px, transparent 16px);
      margin: 2rem 0;
    }

    .math-block {
      overflow-x: auto;
      margin: 1.5rem 0;
      padding: 1rem;
      background: rgba(65, 166, 246, 0.05);
      border: 2px solid var(--pixel-border);
    }
  }

  .article-toc {
    padding: 1.5rem;
    background: var(--pixel-card);
    border: var(--pixel-border-width) solid var(--pixel-border);
    box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);

    .toc-title {
      font-family: var(--pixel-font-title);
      font-size: 10px;
      color: var(--pixel-primary);
      margin-bottom: 1rem;
      text-transform: uppercase;
    }

    .toc-list {
      list-style: none;
      padding: 0;
      a {
        display: block;
        padding: 4px 0;
        font-family: var(--pixel-font-body);
        font-size: 18px;
        color: var(--pixel-text-dim);
        border-bottom: none;
        &:hover { color: var(--pixel-primary); }
      }
    }
  }
}

/* === 文章基础/卡片样式 === */
.article-base {
  .article-cover {
    width: 100%;
    aspect-ratio: 16/9;
    overflow: hidden;
    border-bottom: var(--pixel-border-width) solid var(--pixel-border);
    img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      image-rendering: pixelated;
      transition: transform 0.3s ease;
    }
  }
  &:hover .article-cover img {
    transform: scale(1.05);
  }
  .article-info {
    padding: 1.25rem;
  }
  .article-title {
    font-family: var(--pixel-font-title);
    font-size: 11px;
    color: var(--pixel-primary);
    line-height: 1.6;
    margin-bottom: 0.75rem;
    a { color: inherit; border-bottom: none; &:hover { color: var(--pixel-secondary); } }
  }
  .article-desc {
    font-size: 18px;
    color: var(--pixel-text-dim);
    line-height: 1.6;
    margin-bottom: 0.75rem;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }
  .article-meta {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    font-family: var(--pixel-font-title);
    font-size: 8px;
    color: var(--pixel-text-dim);
    span { display: inline-flex; align-items: center; gap: 4px; }
  }
  .article-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 0.4rem;
    margin-top: 0.75rem;
  }
}

/* === 关于页样式 === */
.about-page {
  .about-header {
    text-align: center;
    margin-bottom: 2rem;
    padding-bottom: 1.5rem;
    border-bottom: var(--pixel-border-width) dashed var(--pixel-border);
    .about-avatar {
      width: 96px;
      height: 96px;
      border: var(--pixel-border-width) solid var(--pixel-primary);
      box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);
      image-rendering: pixelated;
      margin: 0 auto 1rem;
    }
    .about-name {
      font-family: var(--pixel-font-title);
      font-size: 14px;
      color: var(--pixel-primary);
    }
    .about-motto {
      font-family: var(--pixel-font-body);
      font-size: 20px;
      color: var(--pixel-text-dim);
      margin-top: 0.5rem;
    }
  }
  .about-content {
    font-size: 20px;
    line-height: 1.8;
    color: var(--pixel-text);
    h1, h2, h3 { font-family: var(--pixel-font-title); color: var(--pixel-primary); margin: 1.5rem 0 0.75rem; }
    h1 { font-size: 14px; }
    h2 { font-size: 12px; }
    h3 { font-size: 10px; }
    p { margin: 1rem 0; }
    a { color: var(--pixel-primary); border-bottom: 2px solid; &:hover { color: var(--pixel-secondary); } }
  }
}

