---
import Layout from '@/layouts/Layout/Layout.astro';
import Aside from '@/components/Aside/Aside.astro';

interface Props {
  title?: string;
  description?: string;
  cover?: string;
  banner?: boolean;
}

const { title, description, cover, banner = false } = Astro.props;
---
<Layout title={title} description={description} cover={cover}>
  {banner && (
    <div class="home-banner" slot="before">
      <div class="banner-content">
        <h1 class="banner-title">{siteConfig.title}</h1>
        <p class="banner-subtitle" id="typewriter"></p>
      </div>
    </div>
  )}
  <div class="page-layout">
    <div class="page-main">
      <slot />
    </div>
    <Aside />
  </div>
</Layout>

<script is:inline>
  import { siteConfig } from '@/config';
  // 打字机效果
  const el = document.getElementById('typewriter');
  if (el) {
    const texts = siteConfig.typewriter;
    let textIndex = 0, charIndex = 0, isDeleting = false;
    function type() {
      const current = texts[textIndex];
      if (isDeleting) {
        el.textContent = current.substring(0, charIndex - 1);
        charIndex--;
      } else {
        el.textContent = current.substring(0, charIndex + 1);
        charIndex++;
      }
      let delay = isDeleting ? 50 : 100;
      if (!isDeleting && charIndex === current.length) {
        delay = 2000;
        isDeleting = true;
      } else if (isDeleting && charIndex === 0) {
        isDeleting = false;
        textIndex = (textIndex + 1) % texts.length;
        delay = 500;
      }
      setTimeout(type, delay);
    }
    type();
  }
</script>

<style lang="less">
.page-layout {
  display: flex;
  gap: 1.5rem;
  width: 100%;
}
.page-main {
  flex: 1;
  min-width: 0;
}
.home-banner {
  width: 100%;
  padding: 3rem 2rem;
  margin-bottom: 1.5rem;
  background: var(--pixel-card);
  border: var(--pixel-border-width) solid var(--pixel-border);
  box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color);
  text-align: center;
  position: relative;
  overflow: hidden;
  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: repeating-linear-gradient(
      0deg, transparent, transparent 3px, rgba(0,0,0,0.03) 3px, rgba(0,0,0,0.03) 4px
    );
    pointer-events: none;
  }
  .banner-title {
    font-family: var(--pixel-font-title);
    font-size: 16px;
    color: var(--pixel-primary);
    margin-bottom: 1rem;
    text-shadow: 3px 3px 0 var(--pixel-shadow-color);
  }
  .banner-subtitle {
    font-family: var(--pixel-font-body);
    font-size: 22px;
    color: var(--pixel-text-dim);
    min-height: 30px;
  }
}
@media screen and (max-width: 768px) {
  .page-layout { flex-direction: column; }
  .home-banner { padding: 2rem 1rem; }
  .banner-title { font-size: 12px !important; }
}
</style>

