  return allPosts.map(post => ({
    params: { article: post.id },
    props: { post },
  }));
}

const { post } = Astro.props;
const { Content } = await post.render();
const allPosts = await getCollection('blog', ({ data }) => !data.draft);
allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
const currentIndex = allPosts.findIndex(p => p.id === post.id);
const prevPost = currentIndex > 0 ? allPosts[currentIndex - 1] : null;
const nextPost = currentIndex < allPosts.length - 1 ? allPosts[currentIndex + 1] : null;
const articleUrl = `${Astro.site}article/${post.id}`;
---
<Layout title={post.data.title} description={post.data.description} cover={post.data.cover}>
