import path from 'path';
import { fileURLToPath } from 'url';
import { defineConfig } from 'astro/config';
import mdx from '@astrojs/mdx';
import sitemap from '@astrojs/sitemap';
import compress from '@playform/compress';
import remarkMath from 'remark-math';
import remarkDirective from 'remark-directive';
import rehypeKatex from 'rehype-katex';
import rehypeSlug from 'rehype-slug';
import { siteConfig } from './src/config';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

export default defineConfig({
  site: siteConfig.site,
  integrations: [
    mdx(),
    sitemap(),
    compress(),
  ],
  markdown: {
    remarkPlugins: [remarkMath, remarkDirective],
    rehypePlugins: [rehypeKatex, rehypeSlug],
    shikiConfig: {
      theme: 'github-dark',
    },
  },
  vite: {
    resolve: {
      alias: {
        '@': path.resolve(__dirname, './src'),
      },
    },
  },
  build: {
    assets: 'vh_static',
  },
});

{
  "extends": "astro/tsconfigs/strict",
  "compilerOptions": {
    "baseUrl": ".",
    "paths": {
      "@/*": ["src/*"]
    }
  }
}

import { defineCollection, z } from 'astro:content';

const blog = defineCollection({
  type: 'content',
  schema: z.object({
    title: z.string(),
    description: z.string(),
    cover: z.string().optional(),
    date: z.coerce.date(),
    updated: z.coerce.date().optional(),
    tags: z.array(z.string()).default([]),
    categories: z.array(z.string()).default([]),
    draft: z.boolean().default(false),
    pin: z.boolean().default(false),
    toc: z.boolean().default(true),
    comment: z.boolean().default(true),
    reward: z.boolean().default(true),
    livePhoto: z.boolean().default(false),
  }),
});

export const collections = { blog };

export interface NavItem { name: string; link: string; icon?: string; }
export interface PostFrontmatter {
  title: string; description: string; cover?: string; date: Date;
  updated?: Date; tags: string[]; categories: string[];
  draft: boolean; pin: boolean; toc: boolean; comment: boolean; reward: boolean; livePhoto: boolean;
}
export interface FriendItem { name: string; link: string; avatar: string; description: string; }
export interface TalkingItem { content: string; date: string; tags?: string[]; images?: string[]; }
export interface LinkItem { name: string; link: string; avatar: string; description: string; }

export function formatDate(date: Date | string): string {
  const d = new Date(date);
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}
export function formatDateTime(date: Date | string): string {
  const d = new Date(date);
  return `${formatDate(date)} ${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
}
export function getReadingTime(content: string): number {
  const chineseChars = (content.match(/[\u4e00-\u9fff]/g) || []).length;
  const englishWords = content.replace(/[\u4e00-\u9fff]/g, '').split(/\s+/).filter(Boolean).length;
  return Math.max(1, Math.ceil(chineseChars / 400 + englishWords / 200));
}
export function getWordCount(content: string): number {
  const chineseChars = (content.match(/[\u4e00-\u9fff]/g) || []).length;
  const englishWords = content.replace(/[\u4e00-\u9fff]/g, '').split(/\s+/).filter(Boolean).length;
  return chineseChars + englishWords;
}
export function sortByDate(a: { date: Date }, b: { date: Date }): number {
  return new Date(b.date).getTime() - new Date(a.date).getTime();
}
export function getYear(date: Date | string): string {
  return String(new Date(date).getFullYear());
}
export function slugify(text: string): string {
  return text.toLowerCase().replace(/[^\w\u4e00-\u9fff]+/g, '-').replace(/^-+|-+$/g, '');
}

