  .article-desc { font-size: 18px; color: var(--pixel-text-dim); line-height: 1.6; margin-bottom: 0.75rem; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }
  .article-meta { display: flex; flex-wrap: wrap; align-items: center; gap: 0.75rem; font-family: var(--pixel-font-title); font-size: 8px; color: var(--pixel-text-dim); span { display: inline-flex; align-items: center; gap: 4px; } }
  .article-tags { display: flex; flex-wrap: wrap; gap: 0.4rem; margin-top: 0.75rem; }
}

.about-page {
  .about-header { text-align: center; margin-bottom: 2rem; padding-bottom: 1.5rem; border-bottom: var(--pixel-border-width) dashed var(--pixel-border);
    .about-avatar { width: 96px; height: 96px; border: var(--pixel-border-width) solid var(--pixel-primary); box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color); image-rendering: pixelated; margin: 0 auto 1rem; }
    .about-name { font-family: var(--pixel-font-title); font-size: 14px; color: var(--pixel-primary); }
    .about-motto { font-family: var(--pixel-font-body); font-size: 20px; color: var(--pixel-text-dim); margin-top: 0.5rem; }
  }
  .about-content { font-size: 20px; line-height: 1.8; color: var(--pixel-text);
    h1, h2, h3 { font-family: var(--pixel-font-title); color: var(--pixel-primary); margin: 1.5rem 0 0.75rem; }
    h1 { font-size: 14px; } h2 { font-size: 12px; } h3 { font-size: 10px; }
    p { margin: 1rem 0; }
    a { color: var(--pixel-primary); border-bottom: 2px solid; &:hover { color: var(--pixel-secondary); } }
  }
}

---
import '@/styles/Reset.less';
import '@/styles/Base.less';
import Head from '@/components/Head/Head.astro';
import Header from '@/components/Header/Header.astro';
import Footer from '@/components/Footer/Footer.astro';
import BackTop from '@/components/BackTop/BackTop.astro';
import { siteConfig } from '@/config';

interface Props { title?: string; description?: string; cover?: string; }
const { title = siteConfig.title, description = siteConfig.description, cover } = Astro.props;
---
<!DOCTYPE html>
<html lang="zh-CN">
  <Head title={title} description={description} cover={cover} />
  <body>
    <Header />
    <main class="main-inner">
      <div class="main-inner-content vh-animation vh-animation-init">
        <slot />
      </div>
    </main>
    <Footer />
    <BackTop />
  </body>
</html>

<style is:global>
  .main-inner { width: 100%; max-width: var(--vh-main-max-width); margin: 0 auto; padding: 1.5rem; box-sizing: border-box; min-height: calc(100vh - 200px); }
  .main-inner-content { display: flex; gap: 1.5rem; }
  @media screen and (max-width: 768px) { .main-inner-content { flex-direction: column; } }
</style>

---
import Layout from '@/layouts/Layout/Layout.astro';
import Aside from '@/components/Aside/Aside.astro';
import { siteConfig } from '@/config';

interface Props { title?: string; description?: string; cover?: string; }
const { title, description, cover } = Astro.props;
const typewriterTexts = JSON.stringify(siteConfig.typewriter);
---
<Layout title={title} description={description} cover={cover}>
  <div class="home-banner pixel-card">
    <h1 class="banner-title">{siteConfig.title}</h1>
    <p class="banner-subtitle" id="typewriter"></p>
  </div>
  <div class="page-layout">
    <div class="page-main"><slot /></div>
    <Aside />
  </div>
</Layout>

<script is:inline define:vars={{ typewriterTexts }}>
  const texts = JSON.parse(typewriterTexts);
  const el = document.getElementById('typewriter');
  if (el) {
    let ti = 0, ci = 0, del = false;
    function type() {
      const cur = texts[ti];
      if (del) { el.textContent = cur.substring(0, --ci); } else { el.textContent = cur.substring(0, ++ci); }
      let d = del ? 50 : 120;
      if (!del && ci === cur.length) { d = 2000; del = true; }
      else if (del && ci === 0) { del = false; ti = (ti + 1) % texts.length; d = 500; }
      setTimeout(type, d);
    }
    type();
  }
</script>

<style lang="less">
.home-banner { width: 100%; padding: 3rem 2rem; margin-bottom: 1.5rem; text-align: center; position: relative; overflow: hidden;
  &::before { content: ''; position: absolute; inset: 0; background: repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(0,0,0,0.05) 3px, rgba(0,0,0,0.05) 4px); pointer-events: none; }
  .banner-title { font-family: var(--pixel-font-title); font-size: 16px; color: var(--pixel-primary); text-shadow: 4px 4px 0 var(--pixel-shadow-color); margin-bottom: 1rem; }
  .banner-subtitle { font-family: var(--pixel-font-body); font-size: 24px; color: var(--pixel-text-dim); min-height: 30px; }
}
.page-layout { display: flex; gap: 1.5rem; width: 100%; }
.page-main { flex: 1; min-width: 0; }
@media screen and (max-width: 768px) {
  .page-layout { flex-direction: column; }
  .home-banner { padding: 2rem 1rem; }
  .banner-title { font-size: 12px !important; }
}
</style>

---
import { siteConfig } from '@/config';
import Search from '@/components/Search/Search.astro';
import MobileSidebar from '@/components/MobileSidebar/MobileSidebar.astro';
const currentPath = Astro.url.pathname;
---
<header class="vh-header">
  <div class="header-inner">
    <a href="/" class="logo"><span class="logo-icon">◼</span><span class="logo-text">{siteConfig.title}</span></a>
    <nav class="nav-desktop">
      {siteConfig.navbar.map(item => (
        <a href={item.link} class:list={['nav-link', { active: currentPath === item.link || (item.link !== '/' && currentPath.startsWith(item.link)) }]}>{item.name}</a>
      ))}
    </nav>
    <div class="header-actions">
      <Search />
      <button class="mobile-menu-btn" id="mobile-menu-btn" aria-label="菜单"><span></span><span></span><span></span></button>
    </div>
  </div>
  <MobileSidebar />
</header>

<style lang="less">
.vh-header { position: sticky; top: 0; z-index: 100; background: var(--pixel-card); border-bottom: var(--pixel-border-width) solid var(--pixel-border); box-shadow: 0 4px 0 0 var(--pixel-shadow-color); }
.header-inner { max-width: var(--vh-main-max-width); margin: 0 auto; padding: 0 1.5rem; height: 60px; display: flex; align-items: center; justify-content: space-between; gap: 1rem; }
.logo { display: flex; align-items: center; gap: 8px; font-family: var(--pixel-font-title); font-size: 12px; color: var(--pixel-primary) !important; text-decoration: none; border-bottom: none; }
.nav-desktop { display: flex; gap: 2px; flex-wrap: wrap; justify-content: center; }
.nav-link { display: inline-block; padding: 6px 12px; font-family: var(--pixel-font-title); font-size: 8px; color: var(--pixel-text-dim) !important; text-decoration: none; border: 2px solid transparent; text-transform: uppercase; letter-spacing: 1px; transition: all var(--pixel-transition);
  &:hover, &.active { color: var(--pixel-bg) !important; background: var(--pixel-primary); border-color: var(--pixel-border); }
}
.header-actions { display: flex; align-items: center; gap: 0.5rem; }
.mobile-menu-btn { display: none; flex-direction: column; gap: 4px; padding: 8px; background: none; border: 2px solid var(--pixel-border); cursor: pointer; span { display: block; width: 20px; height: 3px; background: var(--pixel-text); } }
@media screen and (max-width: 768px) { .nav-desktop { display: none; } .mobile-menu-btn { display: flex; } }
</style>

<script>
  const btn = document.getElementById('mobile-menu-btn');
  const sidebar = document.getElementById('mobile-sidebar');
  if (btn && sidebar) { btn.addEventListener('click', () => { sidebar.classList.toggle('open'); }); }
</script>

---
import { siteConfig } from '@/config';
---
<aside class="mobile-sidebar" id="mobile-sidebar">
  <nav class="mobile-nav">
    {siteConfig.navbar.map(item => (<a href={item.link} class="mobile-nav-link">{item.name}</a>))}
  </nav>
</aside>
<style lang="less">
.mobile-sidebar { position: fixed; top: 60px; left: -100%; width: 280px; height: calc(100vh - 60px); background: var(--pixel-card); border-right: var(--pixel-border-width) solid var(--pixel-border); box-shadow: 4px 0 0 0 var(--pixel-shadow-color); z-index: 99; transition: left 0.3s ease; overflow-y: auto; padding: 1rem; &.open { left: 0; } }
.mobile-nav { display: flex; flex-direction: column; gap: 4px; }
.mobile-nav-link { display: block; padding: 10px 16px; font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-text-dim) !important; border: 2px solid var(--pixel-border); &:hover { background: var(--pixel-primary); color: var(--pixel-bg) !important; } }
</style>

---
import { siteConfig } from '@/config';
import { getCollection } from 'astro:content';
const allPosts = await getCollection('blog', ({ data }) => !data.draft);
allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
const categories = [...new Set(allPosts.flatMap(p => p.data.categories))];
const tags = [...new Set(allPosts.flatMap(p => p.data.tags))];
const recentPosts = allPosts.slice(0, 5);
---
<aside class="aside pixel-card">
  {siteConfig.sidebar.showAnnouncement && (
    <div class="aside-section">
      <h3 class="aside-title">📢 公告</h3>
      <p class="aside-announcement">{siteConfig.sidebar.announcement}</p>
    </div>
  )}
  <div class="aside-section">
    <h3 class="aside-title">👤 关于</h3>
    <div class="aside-author">
      <div class="author-avatar"><img src="/assets/images/avatar-default.webp" alt={siteConfig.author} width="48" height="48" /></div>
      <div class="author-info">
        <span class="author-name">{siteConfig.author}</span>
        <span class="author-motto">{siteConfig.motto}</span>
      </div>
    </div>
  </div>
  {siteConfig.sidebar.showCategories && categories.length > 0 && (
    <div class="aside-section">
      <h3 class="aside-title">📁 分类</h3>
      <div class="aside-tags">{categories.map(c => (<a href={`/categories/${c}`} class="pixel-tag">{c}</a>))}</div>
    </div>
  )}
  {siteConfig.sidebar.showTags && tags.length > 0 && (
    <div class="aside-section">
      <h3 class="aside-title">🏷️ 标签</h3>
      <div class="aside-tags">{tags.map(t => (<a href={`/tag/${t}`} class="pixel-tag">{t}</a>))}</div>
    </div>
  )}
  {siteConfig.sidebar.showRecentPosts && recentPosts.length > 0 && (
    <div class="aside-section">
      <h3 class="aside-title">📝 最新</h3>
      <ul class="aside-list">{recentPosts.map(post => (<li><a href={`/article/${post.id}`}>{post.data.title}</a></li>))}</ul>
    </div>
  )}
</aside>

<style lang="less">
.aside { width: var(--vh-aside-width); min-width: var(--vh-aside-width); max-height: calc(100vh - 100px); overflow-y: auto; position: sticky; top: 80px; padding: 1.25rem; }
.aside-section { margin-bottom: 1.5rem; padding-bottom: 1.5rem; border-bottom: 2px dashed var(--pixel-border); &:last-child { border-bottom: none; } }
.aside-title { font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-primary); margin-bottom: 0.75rem; text-transform: uppercase; }
.aside-announcement { font-size: 18px; color: var(--pixel-text-dim); line-height: 1.6; }
.aside-author { display: flex; align-items: center; gap: 0.75rem;
  .author-avatar { width: 48px; height: 48px; border: 3px solid var(--pixel-primary); box-shadow: 3px 3px 0 0 var(--pixel-shadow-color); img { width: 100%; height: 100%; object-fit: cover; } }
  .author-info { display: flex; flex-direction: column; gap: 2px; }
  .author-name { font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-primary); }
  .author-motto { font-size: 16px; color: var(--pixel-text-dim); }
}
.aside-tags { display: flex; flex-wrap: wrap; gap: 6px; a { text-decoration: none; border-bottom: none; } }
.aside-list { list-style: none; padding: 0; li { padding: 4px 0; a { font-size: 17px; color: var(--pixel-text-dim); &:hover { color: var(--pixel-primary); } } } }
@media screen and (max-width: 768px) { .aside { display: none; } }
</style>

---
import { formatDate } from '@/utils';
interface Props { title: string; description: string; cover?: string; date: Date; tags: string[]; categories: string[]; readingTime?: number; wordCount?: number; link: string; pin?: boolean; }
const { title, description, cover, date, tags, categories, readingTime, wordCount, link, pin } = Astro.props;
---
<a href={link} class="article-card article-base pixel-card">
  {pin && <span class="pin-badge">📌 置顶</span>}
  {cover && <div class="article-cover"><img src={cover} alt={title} loading="lazy" /></div>}
  <div class="article-info">
    <h2 class="article-title">{title}</h2>
    <p class="article-desc">{description}</p>
    <div class="article-meta">
      <span>📅 {formatDate(date)}</span>
      {readingTime && <span>⏱️ {readingTime}分钟</span>}
      {wordCount && <span>📝 {wordCount}字</span>}
    </div>
    <div class="article-tags">{tags.map(tag => (<span class="pixel-tag">{tag}</span>))}</div>
  </div>
</a>
<style lang="less">
.article-card { display: block; margin-bottom: 1.5rem; text-decoration: none; border-bottom: none; position: relative; overflow: hidden; }
.pin-badge { position: absolute; top: 8px; right: 8px; z-index: 2; font-family: var(--pixel-font-title); font-size: 8px; padding: 4px 8px; background: var(--pixel-secondary); color: var(--pixel-bg); border: 2px solid var(--pixel-border); }
</style>

---
import { getCollection } from 'astro:content';
import { formatDate, getYear } from '@/utils';
const allPosts = await getCollection('blog', ({ data }) => !data.draft);
allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
const yearMap = new Map<string, typeof allPosts>();
allPosts.forEach(post => { const y = getYear(post.data.date); if (!yearMap.has(y)) yearMap.set(y, []); yearMap.get(y)!.push(post); });
---
<div class="archive-page">
  <h1 class="pixel-page-title">📜 归档</h1>
  <div class="archive-list">
    {[...yearMap.entries()].map(([year, posts]) => (
      <div class="archive-year">
        <h2 class="archive-year-title">◄ {year} ►</h2>
        <ul class="archive-posts">
          {posts.map(post => (<li class="archive-item"><span class="archive-date">{formatDate(post.data.date)}</span><a href={`/article/${post.id}`} class="archive-link">{post.data.title}</a></li>))}
        </ul>
      </div>
    ))}
  </div>
</div>
<style lang="less">
.pixel-page-title { font-family: var(--pixel-font-title); font-size: 14px; color: var(--pixel-primary); text-shadow: 3px 3px 0 var(--pixel-shadow-color); margin-bottom: 1.5rem; }
.archive-year { margin-bottom: 2rem; }
.archive-year-title { font-family: var(--pixel-font-title); font-size: 11px; color: var(--pixel-secondary); padding: 8px 16px; background: var(--pixel-card); border: var(--pixel-border-width) solid var(--pixel-border); box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color); display: inline-block; margin-bottom: 1rem; }
.archive-posts { list-style: none; padding: 0; }
.archive-item { display: flex; gap: 1rem; align-items: baseline; padding: 8px 0; border-bottom: 2px dotted var(--pixel-border); }
.archive-date { font-family: var(--pixel-font-title); font-size: 8px; color: var(--pixel-text-dim); white-space: nowrap; }
.archive-link { font-size: 18px; color: var(--pixel-text); &:hover { color: var(--pixel-primary); } }
</style>

---
interface Props { currentPage: number; totalPages: number; baseUrl?: string; }
const { currentPage, totalPages, baseUrl = '' } = Astro.props;
---
{totalPages > 1 && (
  <nav class="pagination">
    {currentPage > 1 && <a href={`${baseUrl}/${currentPage - 1 === 1 ? '' : currentPage - 1}`} class="pixel-btn">◄ 上一页</a>}
    {Array.from({ length: totalPages }, (_, i) => i + 1).map(page => (
      <a href={page === 1 ? `${baseUrl}/` : `${baseUrl}/${page}`} class:list={['pixel-btn', { active: page === currentPage }]}>{page}</a>
    ))}
    {currentPage < totalPages && <a href={`${baseUrl}/${currentPage + 1}`} class="pixel-btn">下一页 ►</a>}
  </nav>
)}
<style lang="less">
.pagination { display: flex; justify-content: center; flex-wrap: wrap; gap: 4px; margin: 2rem 0; .pixel-btn { font-size: 8px; padding: 6px 10px; background: var(--pixel-card); color: var(--pixel-text-dim); &:hover, &.active { background: var(--pixel-primary); color: var(--pixel-bg); } } }
</style>

---
import { siteConfig } from '@/config';
---
<footer class="vh-footer">
  <div class="footer-inner">
    <p class="footer-text">© {new Date().getFullYear()} {siteConfig.author} | Powered by <a href="https://astro.build" target="_blank">Astro</a></p>
    <p class="footer-sub">◼ Pixel Astro Blog ◼ {siteConfig.motto}</p>
  </div>
</footer>
<style lang="less">
.vh-footer { background: var(--pixel-card); border-top: var(--pixel-border-width) solid var(--pixel-border); margin-top: auto; }
.footer-inner { max-width: var(--vh-main-max-width); margin: 0 auto; padding: 1.5rem; text-align: center; }
.footer-text { font-family: var(--pixel-font-title); font-size: 8px; color: var(--pixel-text-dim); a { color: var(--pixel-primary); border-bottom: 2px solid; } }
.footer-sub { font-family: var(--pixel-font-body); font-size: 16px; color: rgba(244,244,244,0.28); margin-top: 0.5rem; }
</style>

---
---
<button class="back-top pixel-btn" id="back-top" title="返回顶部">▲ TOP</button>
<style lang="less">
.back-top { position: fixed; bottom: 2rem; right: 2rem; z-index: 90; opacity: 0; transform: translateY(20px); transition: all 0.3s ease; pointer-events: none;
  &.visible { opacity: 1; transform: translateY(0); pointer-events: auto; }
  &:active { transform: translate(2px, 2px); box-shadow: 2px 2px 0 0 var(--pixel-shadow-color); }
}
</style>
<script>
  const b = document.getElementById('back-top');
  if (b) { window.addEventListener('scroll', () => { b.classList.toggle('visible', window.scrollY > 300); }); b.addEventListener('click', () => { window.scrollTo({ top: 0, behavior: 'smooth' }); }); }
</script>

---
---
<div class="search-wrapper">
  <button class="search-btn pixel-btn" id="search-btn">🔍</button>
  <div class="search-modal" id="search-modal">
    <div class="search-overlay" id="search-overlay"></div>
    <div class="search-content pixel-card">
      <input type="text" class="pixel-input" id="search-input" placeholder="输入关键词搜索..." />
      <div class="search-results" id="search-results"></div>
    </div>
  </div>
</div>
<style lang="less">
.search-wrapper { display: flex; align-items: center; }
.search-btn { font-size: 14px; padding: 4px 8px; background: var(--pixel-card); }
.search-modal { display: none; position: fixed; inset: 0; z-index: 200; &.open { display: flex; align-items: flex-start; justify-content: center; padding-top: 10vh; } }
.search-overlay { position: absolute; inset: 0; background: rgba(0,0,0,0.7); }
.search-content { position: relative; width: 90%; max-width: 600px; padding: 1.5rem; z-index: 1; }
.search-results { margin-top: 1rem; max-height: 60vh; overflow-y: auto; .search-item { padding: 0.75rem; margin-bottom: 4px; border: 2px solid var(--pixel-border); background: var(--pixel-code-bg); a { display: block; font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-primary); } p { font-size: 16px; color: var(--pixel-text-dim); margin-top: 4px; } } }
</style>
<script>
  const btn = document.getElementById('search-btn'), modal = document.getElementById('search-modal'), overlay = document.getElementById('search-overlay'), input = document.getElementById('search-input'), results = document.getElementById('search-results');
  let searchData: any[] = [];
  function openSearch() { modal?.classList.add('open'); setTimeout(() => (input as HTMLInputElement)?.focus(), 100); }
  function closeSearch() { modal?.classList.remove('open'); (input as HTMLInputElement).value = ''; results!.innerHTML = ''; }
  btn?.addEventListener('click', openSearch); overlay?.addEventListener('click', closeSearch);
  document.addEventListener('keydown', (e) => { if (e.key === 'Escape') closeSearch(); });
  input?.addEventListener('input', async () => {
    const q = (input as HTMLInputElement).value.trim().toLowerCase();
    if (!q) { results!.innerHTML = ''; return; }
    if (!searchData.length) { try { const r = await fetch('/vh_static/search.json'); searchData = await r.json(); } catch { return; } }
    const f = searchData.filter(i => i.title.toLowerCase().includes(q) || i.content.toLowerCase().includes(q));
    results!.innerHTML = f.slice(0, 10).map(i => `<div class="search-item"><a href="${i.url}">${i.title}</a><p>${i.content.substring(0, 120)}...</p></div>`).join('');
  });
</script>

---
import { siteConfig } from '@/config';
---
{siteConfig.comment.enable && (<div class="comment-section"><h3 class="comment-title">💬 评论</h3><div id="comment-container"></div></div>)}
<style lang="less">
.comment-section { margin-top: 2rem; padding-top: 1.5rem; border-top: var(--pixel-border-width) dashed var(--pixel-border); }
.comment-title { font-family: var(--pixel-font-title); font-size: 10px; color: var(--pixel-primary); margin-bottom: 1rem; }
</style>

---
import { siteConfig } from '@/config';
interface Props { title: string; url: string; }
const { title, url } = Astro.props;
---
<div class="copyright">
  <p class="copyright-title">📜 版权声明</p>
  <p>本文标题：<a href={url}>{title}</a></p>
  <p>作者：{siteConfig.author}</p>
  <p>本文链接：<a href={url}>{url}</a></p>
  <p>版权声明：本博客所有文章除特别声明外，均采用 CC BY-NC-SA 4.0 许可协议。</p>
</div>
<style lang="less">
.copyright { margin-top: 2rem; padding: 1rem 1.25rem; background: var(--pixel-code-bg); border: var(--pixel-border-width) solid var(--pixel-border); box-shadow: var(--pixel-shadow-offset) var(--pixel-shadow-offset) 0 0 var(--pixel-shadow-color); font-size: 16px; color: var(--pixel-text-dim); line-height: 1.8;
  a { color: var(--pixel-primary); border-bottom: 2px solid; }
  .copyright-title { font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-secondary); margin-bottom: 0.5rem; }
}
</style>

---
interface Props { prev?: { title: string; slug: string } | null; next?: { title: string; slug: string } | null; }
const { prev, next } = Astro.props;
---
{(prev || next) && (
