  if (el) { let ti=0,ci=0,d=false; function t(){const c=texts[ti];if(d){el.textContent=c.substring(0,--ci);}else{el.textContent=c.substring(0,++ci);}let dl=d?50:120;if(!d&&ci===c.length){dl=2000;d=true;}else if(d&&ci===0){d=false;ti=(ti+1)%texts.length;dl=500;}setTimeout(t,dl);}t(); }
