import { siteConfig } from '@/config';
import Search from '@/components/Search/Search.astro';
import MobileSidebar from '@/components/MobileSidebar/MobileSidebar.astro';
const currentPath = Astro.url.pathname;
---
<header class="vh-header">
  <div class="header-inner">
    <a href="/" class="logo">
      <div class="logo-icon">P</div>
      <span class="logo-text">PIXEL.BLOG</span>
    </a>
    <nav class="nav-desktop">
      {siteConfig.navbar.map(item => (
        <a href={item.link} class:list={['nav-link', { active: currentPath === item.link || (item.link !== '/' && currentPath.startsWith(item.link)) }]}>
          {item.name}
        </a>
      ))}
    </nav>
    <div class="header-actions">
      <Search />
      <button class="mobile-menu-btn pixel-btn" id="mobile-menu-btn" aria-label="菜单">
        <span></span><span></span><span></span>
      </button>
    </div>
  </div>
  <MobileSidebar />
</header>

<style lang="less">
.vh-header {
  position: sticky; top: 0; z-index: 100;
  background: rgba(232, 224, 213, 0.95); backdrop-filter: blur(12px);
  border-bottom: 4px solid var(--pixel-dark);
}
.header-inner {
  max-width: var(--vh-main-max-width); margin: 0 auto; padding: 0 1.5rem;
  height: 64px; display: flex; align-items: center; justify-content: space-between; gap: 1rem;
}
.logo {
  display: flex; align-items: center; gap: 10px; text-decoration: none; border-bottom: none;
  .logo-icon {
    width: 40px; height: 40px; background: var(--pixel-accent);
    border: 4px solid var(--pixel-dark); display: flex; align-items: center; justify-content: center;
    font-family: var(--pixel-font-title); color: white; font-size: 14px;
    box-shadow: 3px 3px 0 0 var(--pixel-dark);
  }
  .logo-text {
    font-family: var(--pixel-font-title); font-size: 14px; color: var(--pixel-dark);
    &:hover { animation: glitch 0.3s ease both; color: var(--pixel-accent); }
  }
}
.nav-desktop { display: flex; gap: 2px; flex-wrap: wrap; justify-content: center; }
.nav-link {
  position: relative; overflow: hidden; display: inline-block;
  padding: 6px 12px; font-family: var(--pixel-font-body); font-size: 16px;
  color: var(--pixel-dark); font-weight: bold; text-decoration: none;
  &::after {
    content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 4px;
    background: var(--pixel-accent); transition: width 0.3s;
  }
  &:hover::after, &.active::after { width: 100%; }
  &:hover { color: var(--pixel-accent); }
}
.header-actions { display: flex; align-items: center; gap: 0.5rem; }
.mobile-menu-btn {
  display: none; flex-direction: column; gap: 4px; padding: 8px;
  background: var(--pixel-purple);
  span { display: block; width: 20px; height: 3px; background: white; }
}
@keyframes glitch {
  0% { transform: translate(0); } 20% { transform: translate(-2px, 2px); }
  40% { transform: translate(-2px, -2px); } 60% { transform: translate(2px, 2px); }
  80% { transform: translate(2px, -2px); } 100% { transform: translate(0); }
}
@media screen and (max-width: 768px) { .nav-desktop { display: none; } .mobile-menu-btn { display: flex; } }
</style>

<script>
  const btn = document.getElementById('mobile-menu-btn');
  const sidebar = document.getElementById('mobile-sidebar');
  if (btn && sidebar) { btn.addEventListener('click', () => { sidebar.classList.toggle('open'); }); }
</script>

---
import { siteConfig } from '@/config';
---
<aside class="mobile-sidebar" id="mobile-sidebar">
  <div class="mobile-header">
    <span class="pixel-font">MENU</span>
    <button class="pixel-btn close-btn" onclick="document.getElementById('mobile-sidebar').classList.remove('open')">✕</button>
  </div>
  <nav class="mobile-nav">
    {siteConfig.navbar.map(item => (
      <a href={item.link} class="mobile-nav-link" onclick="document.getElementById('mobile-sidebar').classList.remove('open')">{item.name}</a>
    ))}
  </nav>
</aside>

<style lang="less">
.mobile-sidebar {
  position: fixed; top: 0; left: -100%; width: 288px; height: 100vh;
  background: var(--pixel-bg); border-right: 4px solid var(--pixel-dark);
  box-shadow: 6px 0 0 0 var(--pixel-dark); z-index: 99;
  transition: left 0.3s ease; overflow-y: auto; padding: 1.5rem;
  &.open { left: 0; }
}
.mobile-header {
  display: flex; justify-content: space-between; align-items: center; margin-bottom: 2rem;
  .pixel-font { font-family: var(--pixel-font-title); font-size: 12px; color: var(--pixel-dark); }
  .close-btn { padding: 6px 10px; background: var(--pixel-accent); color: white; font-size: 14px; }
}
.mobile-nav { display: flex; flex-direction: column; gap: 4px; }
.mobile-nav-link {
  display: block; padding: 12px 16px;
  font-family: var(--pixel-font-body); font-size: 18px; font-weight: bold;
  color: var(--pixel-dark); text-decoration: none;
  border: 3px solid var(--pixel-dark); background: var(--pixel-bg-grid);
  &:hover { background: var(--pixel-accent); color: white; }
}
</style>

---
import { siteConfig } from '@/config';
import { getCollection } from 'astro:content';
const allPosts = await getCollection('blog', ({ data }) => !data.draft);
allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
const categories = [...new Set(allPosts.flatMap(p => p.data.categories))];
const tags = [...new Set(allPosts.flatMap(p => p.data.tags))];
const recentPosts = allPosts.slice(0, 3);
const catColors = ['var(--pixel-accent)', 'var(--pixel-secondary)', 'var(--pixel-yellow)', 'var(--pixel-purple)', 'var(--pixel-blue)', 'var(--pixel-orange)'];
const tagColors = ['var(--pixel-yellow)', 'var(--pixel-secondary)', 'var(--pixel-purple)', 'var(--pixel-accent)', 'var(--pixel-green)', 'var(--pixel-blue)', 'var(--pixel-pink)', 'var(--pixel-cyan)', 'var(--pixel-orange)'];
---
<aside class="aside">
  <!-- 个人信息卡 -->
  <div class="aside-card profile-card">
    <div class="profile-avatar-wrap">
      <img src="/assets/images/avatar-default.webp" alt={siteConfig.author} class="profile-avatar" width="96" height="96" />
      <div class="profile-badge">✓</div>
    </div>
    <h3 class="pixel-font profile-name">{siteConfig.author}</h3>
    <p class="profile-motto">{siteConfig.motto}</p>
    <div class="profile-stats">
      <div class="stat-item"><span class="stat-num accent">{allPosts.length}</span><span class="stat-label">文章</span></div>
      <div class="stat-divider"></div>
      <div class="stat-item"><span class="stat-num secondary">{categories.length}</span><span class="stat-label">分类</span></div>
      <div class="stat-divider"></div>
      <div class="stat-item"><span class="stat-num purple">{tags.length}</span><span class="stat-label">标签</span></div>
    </div>
    <div class="profile-social">
      <a href="https://github.com" target="_blank" class="social-btn github" title="GitHub">GH</a>
      <a href="#" class="social-btn twitter" title="Twitter">TW</a>
      <a href="#" class="social-btn email" title="Email">✉</a>
      <a href="/rss.xml" class="social-btn rss" title="RSS">RSS</a>
    </div>
  </div>

  <!-- 分类 -->
  {siteConfig.sidebar.showCategories && categories.length > 0 && (
  <div class="aside-card">
    <h3 class="aside-title">📁 文章分类</h3>
    <div class="category-list">
      {categories.map((cat, i) => (
        <a href={`/categories/${cat}`} class="category-item">
          <span class="cat-color" style={`background: ${catColors[i % catColors.length]}`}></span>
          <span class="cat-name">{cat}</span>
          <span class="cat-count">{allPosts.filter(p => p.data.categories.includes(cat)).length}</span>
        </a>
      ))}
    </div>
  </div>
  )}

  <!-- 标签云 -->
  {siteConfig.sidebar.showTags && tags.length > 0 && (
  <div class="aside-card">
    <h3 class="aside-title">🏷️ 标签云</h3>
    <div class="tag-cloud">
      {tags.map((tag, i) => (
        <a href={`/tag/${tag}`} class="tag-pixel" style={`background: ${tagColors[i % tagColors.length]}`}>{tag}</a>
      ))}
    </div>
  </div>
  )}

  <!-- 推荐文章 -->
  {siteConfig.sidebar.showRecentPosts && recentPosts.length > 0 && (
  <div class="aside-card">
    <h3 class="aside-title">⭐ 推荐文章</h3>
    <div class="rec-list">
      {recentPosts.map(post => (
        <a href={`/article/${post.id}`} class="rec-item">
          <div class="rec-thumb">
            <img src={post.data.cover || '/assets/images/avatar-default.webp'} alt={post.data.title} width="64" height="64" />
          </div>
          <div class="rec-info">
            <h4 class="rec-title">{post.data.title}</h4>
            <span class="rec-date">{post.data.date.toLocaleDateString('zh-CN')}</span>
          </div>
        </a>
      ))}
    </div>
  </div>
  )}

  <!-- 音乐 -->
  <div class="aside-card">
    <h3 class="aside-title">🎵 音乐</h3>
    <div class="music-player">
      <div class="music-disc">♫</div>
      <div class="music-info">
        <div class="music-title">8-Bit Adventure</div>
        <div class="music-artist">Pixel Artist</div>
      </div>
    </div>
    <div class="music-controls">
      <button class="pixel-btn music-btn">◁</button>
      <button class="pixel-btn music-btn play">▶</button>
      <button class="pixel-btn music-btn">▷</button>
      <div class="music-bars">
        <span></span><span></span><span></span><span></span><span></span>
      </div>
    </div>
    <div class="pixel-progress"><div class="pixel-progress-bar" style="width: 45%"></div></div>
  </div>
</aside>

<style lang="less">
.aside { width: var(--vh-aside-width); min-width: var(--vh-aside-width); display: flex; flex-direction: column; gap: 1.5rem; }
.aside-card {
  background: var(--pixel-bg-grid); border: 4px solid var(--pixel-dark);
  box-shadow: 6px 6px 0 0 var(--pixel-dark); padding: 1.5rem;
  transition: all 0.15s ease;
  &:hover { transform: translate(-2px, -2px); box-shadow: 8px 8px 0 0 var(--pixel-dark); }
}
.aside-title {
  font-family: var(--pixel-font-title); font-size: 10px; color: var(--pixel-dark);
  margin-bottom: 1rem; display: flex; align-items: center; gap: 8px;
}

/* 个人信息 */
.profile-card { text-align: center; }
.profile-avatar-wrap { position: relative; display: inline-block; margin-bottom: 1rem; }
.profile-avatar {
  width: 96px; height: 96px; border: 4px solid var(--pixel-dark);
  box-shadow: 4px 4px 0 0 var(--pixel-dark); image-rendering: pixelated;
}
.profile-badge {
  position: absolute; bottom: -2px; right: -2px;
  width: 28px; height: 28px; background: var(--pixel-green);
  border: 3px solid var(--pixel-dark); display: flex; align-items: center; justify-content: center;
  color: white; font-size: 14px; font-weight: bold;
}
.profile-name { font-family: var(--pixel-font-title); font-size: 12px; color: var(--pixel-dark); margin-bottom: 0.5rem; }
.profile-motto { font-size: 16px; color: var(--pixel-text-dim); margin-bottom: 1.25rem; }
.profile-stats { display: flex; justify-content: center; gap: 1rem; margin-bottom: 1.25rem; }
.stat-item { text-align: center; }
.stat-num { font-family: var(--pixel-font-title); font-size: 16px; display: block; &.accent { color: var(--pixel-accent); } &.secondary { color: var(--pixel-secondary); } &.purple { color: var(--pixel-purple); } }
.stat-label { font-size: 12px; color: var(--pixel-text-dim); }
.stat-divider { width: 1px; background: rgba(26,26,46,0.2); }
.profile-social { display: flex; justify-content: center; gap: 10px; }
.social-btn {
  display: flex; align-items: center; justify-content: center;
  width: 36px; height: 36px; border: 3px solid var(--pixel-dark);
  box-shadow: 3px 3px 0 0 var(--pixel-dark); color: white;
  font-family: var(--pixel-font-title); font-size: 9px; text-decoration: none;
  transition: all 0.15s ease;
  &.github { background: var(--pixel-dark); }
  &.twitter { background: var(--pixel-blue); }
  &.email { background: var(--pixel-pink); }
  &.rss { background: var(--pixel-orange); }
  &:hover { transform: translate(-1px, -1px); box-shadow: 4px 4px 0 0 var(--pixel-dark); }
}

/* 分类 */
.category-list { display: flex; flex-direction: column; gap: 4px; }
.category-item {
  display: flex; align-items: center; justify-content: space-between;
  padding: 8px 10px; border: 2px solid transparent; transition: all 0.2s;
  text-decoration: none; color: var(--pixel-dark);
  &:hover { background: var(--pixel-bg); border-color: var(--pixel-dark); }
}
.cat-color { width: 12px; height: 12px; border: 2px solid var(--pixel-dark); margin-right: 8px; flex-shrink: 0; }
.cat-name { flex: 1; font-size: 16px; }
.cat-count {
  font-family: var(--pixel-font-title); font-size: 9px;
  background: var(--pixel-bg); border: 2px solid var(--pixel-dark); padding: 2px 6px;
}

/* 标签云 */
.tag-cloud { display: flex; flex-wrap: wrap; gap: 8px; }
.tag-pixel {
  display: inline-block; padding: 4px 10px; font-size: 13px; font-weight: bold;
  color: var(--pixel-dark); border: 3px solid var(--pixel-dark);
  box-shadow: 3px 3px 0 0 var(--pixel-dark); text-decoration: none;
  transition: all 0.2s;
  &:hover { transform: translate(-1px, -1px); box-shadow: 4px 4px 0 0 var(--pixel-dark); background: var(--pixel-accent) !important; color: white !important; }
}

/* 推荐文章 */
.rec-list { display: flex; flex-direction: column; gap: 1rem; }
.rec-item { display: flex; gap: 12px; text-decoration: none; color: var(--pixel-dark); &:hover .rec-title { color: var(--pixel-accent); } }
.rec-thumb {
  width: 64px; height: 64px; flex-shrink: 0; overflow: hidden;
  border: 3px solid var(--pixel-dark); box-shadow: 2px 2px 0 0 var(--pixel-dark);
  img { width: 100%; height: 100%; object-fit: cover; image-rendering: pixelated; }
}
.rec-info { min-width: 0; }
.rec-title { font-size: 14px; font-weight: bold; transition: color 0.2s; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
.rec-date { font-size: 12px; color: var(--pixel-text-dim); }

/* 音乐 */
.music-player { display: flex; align-items: center; gap: 12px; margin-bottom: 12px; }
.music-disc {
  width: 48px; height: 48px; background: var(--pixel-purple);
  border: 3px solid var(--pixel-dark); display: flex; align-items: center; justify-content: center;
  color: white; font-size: 20px; animation: spin 3s linear infinite;
}
@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
.music-info { min-width: 0; }
.music-title { font-size: 15px; font-weight: bold; color: var(--pixel-dark); }
.music-artist { font-size: 13px; color: var(--pixel-text-dim); }
.music-controls { display: flex; align-items: center; gap: 4px; margin-bottom: 8px; }
.music-btn { padding: 4px 8px; background: var(--pixel-dark); color: white; font-size: 12px; &.play { background: var(--pixel-accent); } }
.music-bars { display: flex; align-items: flex-end; gap: 2px; height: 24px; margin-left: 8px; flex: 1;
  span { width: 4px; background: var(--pixel-accent); animation: music-wave 0.5s ease-in-out infinite alternate;
    &:nth-child(1) { height: 8px; animation-delay: 0s; }
    &:nth-child(2) { height: 16px; animation-delay: 0.1s; }
    &:nth-child(3) { height: 12px; animation-delay: 0.2s; }
    &:nth-child(4) { height: 20px; animation-delay: 0.3s; }
    &:nth-child(5) { height: 10px; animation-delay: 0.15s; }
  }
}
@keyframes music-wave { from { height: 8px; } to { height: 24px; } }
.pixel-progress { background: var(--pixel-bg); border: 3px solid var(--pixel-dark); height: 12px; overflow: hidden; }
.pixel-progress-bar {
  background: repeating-linear-gradient(45deg, var(--pixel-accent), var(--pixel-accent) 10px, #c0392b 10px, #c0392b 20px);
  height: 100%; border-right: 3px solid var(--pixel-dark);
}

@media screen and (max-width: 768px) { .aside { display: none; } }
</style>

---
import { formatDate } from '@/utils';
interface Props { title: string; description: string; cover?: string; date: Date; tags: string[]; categories: string[]; readingTime?: number; wordCount?: number; link: string; pin?: boolean; }
const { title, description, cover, date, tags, categories, readingTime, wordCount, link, pin } = Astro.props;
const tagColors = ['var(--pixel-yellow)', 'var(--pixel-secondary)', 'var(--pixel-purple)', 'var(--pixel-accent)', 'var(--pixel-green)', 'var(--pixel-blue)', 'var(--pixel-pink)', 'var(--pixel-cyan)'];
---
<a href={link} class="article-card pixel-card">
  <div class="card-cover">
    <div class="cover-wrap">
      <img src={cover || '/assets/images/avatar-default.webp'} alt={title} loading="lazy" />
      {pin && <span class="top-badge">置顶</span>}
      <div class="cover-bottom">
        {readingTime && <span class="read-badge">⏱ {readingTime}分钟</span>}
        {wordCount && <span class="word-badge">📝 {wordCount}字</span>}
      </div>
    </div>
  </div>
  <div class="card-content">
    <div class="card-meta">
      {categories.length > 0 && <span class="category-pixel">{categories[0]}</span>}
      <span class="meta-date">📅 {formatDate(date)}</span>
    </div>
    <h2 class="card-title">{title}</h2>
    <p class="card-desc">{description}</p>
    <div class="card-footer">
      <div class="card-tags">
        {tags.map((tag, i) => (<span class="tag-pixel" style={`background: ${tagColors[i % tagColors.length]}`}>{tag}</span>))}
      </div>
      <span class="read-btn pixel-btn">阅读 ▸</span>
    </div>
  </div>
</a>

<style lang="less">
.article-card {
  display: flex; gap: 1.25rem; padding: 1.25rem;
  text-decoration: none; border-bottom: none; position: relative;
  @media (max-width: 768px) { flex-direction: column; }
}
.card-cover { width: 40%; flex-shrink: 0; @media (max-width: 768px) { width: 100%; } }
.cover-wrap {
  position: relative; overflow: hidden; border: 4px solid var(--pixel-dark);
  img { width: 100%; height: 200px; object-fit: cover; image-rendering: pixelated; transition: transform 0.5s; }
  &:hover img { transform: scale(1.1); }
}
.top-badge {
  position: absolute; top: 8px; left: 8px;
  background: var(--pixel-accent); color: white; font-size: 11px; font-weight: bold;
  border: 2px solid var(--pixel-dark); box-shadow: 2px 2px 0 0 var(--pixel-dark);
  padding: 2px 8px; animation: pixel-bounce 2s infinite;
}
@keyframes pixel-bounce { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-6px); } }
.cover-bottom {
  position: absolute; bottom: 0; left: 0; right: 0;
  background: linear-gradient(to top, rgba(0,0,0,0.7), transparent);
  padding: 8px; display: flex; gap: 6px;
}
.read-badge, .word-badge {
  font-size: 11px; padding: 2px 8px; color: white; font-weight: bold;
  border: 2px solid var(--pixel-dark); box-shadow: 2px 2px 0 0 var(--pixel-dark);
}
.read-badge { background: var(--pixel-blue); }
.word-badge { background: var(--pixel-purple); }
.card-content { flex: 1; display: flex; flex-direction: column; min-width: 0; }
.card-meta { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; flex-wrap: wrap; }
.category-pixel {
  background: var(--pixel-secondary); color: white; font-size: 12px; font-weight: bold;
  border: 2px solid var(--pixel-dark); box-shadow: 2px 2px 0 0 var(--pixel-dark); padding: 2px 8px;
}
.meta-date { font-size: 14px; color: var(--pixel-text-dim); }
.card-title {
  font-size: 20px; font-weight: bold; color: var(--pixel-dark); line-height: 1.5;
  margin-bottom: 8px; transition: color 0.2s;
  &:hover { color: var(--pixel-accent); }
}
.card-desc {
  font-size: 15px; color: var(--pixel-text-dim); line-height: 1.6; margin-bottom: 1rem;
  display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;
}
.card-footer { margin-top: auto; display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 8px; }
.card-tags { display: flex; gap: 6px; flex-wrap: wrap; }
.tag-pixel {
  display: inline-block; padding: 3px 8px; font-size: 12px; font-weight: bold;
  color: var(--pixel-dark); border: 3px solid var(--pixel-dark);
  box-shadow: 2px 2px 0 0 var(--pixel-dark); transition: all 0.2s;
  &:hover { transform: translate(-1px, -1px); box-shadow: 3px 3px 0 0 var(--pixel-dark); }
}
.read-btn {
  background: var(--pixel-blue); color: white; font-family: var(--pixel-font-body);
  font-size: 14px; padding: 6px 14px; border: 3px solid var(--pixel-dark);
  box-shadow: 3px 3px 0 0 var(--pixel-dark); cursor: pointer;
  &:hover { transform: translate(-1px, -1px); box-shadow: 4px 4px 0 0 var(--pixel-dark); }
  &:active { transform: translate(3px, 3px); box-shadow: 0 0 0 0 var(--pixel-dark); }
}
</style>

---
import { siteConfig } from '@/config';
const typewriterTexts = JSON.stringify(siteConfig.typewriter);
---
<div class="home-banner">
  <div class="banner-decorations">
    <div class="deco-block d1"></div><div class="deco-block d2"></div>
    <div class="deco-block d3"></div><div class="deco-block d4"></div>
    <div class="deco-block d5"></div>
  </div>
  <div class="banner-inner">
    <div class="avatar-wrap">
      <img src="/assets/images/avatar-default.webp" alt={siteConfig.author} class="banner-avatar" width="128" height="128" />
      <div class="avatar-badge">🎮</div>
    </div>
    <h1 class="banner-title pixel-font">PIXEL DEVELOPER</h1>
    <p class="banner-subtitle" id="main-typewriter"></p>
    <div class="banner-actions">
      <a href="/archives" class="pixel-btn accent">🚀 开始探索</a>
      <a href="https://github.com" target="_blank" class="pixel-btn yellow">🐱 GitHub</a>
    </div>
  </div>
  <div class="banner-bottom-line"></div>
</div>

<style lang="less">
.home-banner {
  position: relative; background: var(--pixel-secondary);
  border-bottom: 4px solid var(--pixel-dark); overflow: hidden;
}
.banner-decorations { position: absolute; inset: 0; pointer-events: none;
  &::before {
    content: ''; position: absolute; inset: 0; opacity: 0.1;
    background: repeating-linear-gradient(0deg, transparent, transparent 2px, var(--pixel-dark) 2px, var(--pixel-dark) 4px);
  }
}
.deco-block {
  position: absolute; border: 2px solid var(--pixel-dark); animation: float 4s ease-in-out infinite;
  &.d1 { top: 12%; left: 10%; width: 24px; height: 24px; background: var(--pixel-yellow); border-width: 3px; animation-delay: 0s; }
  &.d2 { top: 20%; right: 15%; width: 16px; height: 16px; background: var(--pixel-accent); animation-delay: 1s; }
  &.d3 { bottom: 25%; left: 20%; width: 20px; height: 20px; background: var(--pixel-purple); animation-delay: 2s; }
  &.d4 { top: 30%; left: 60%; width: 12px; height: 12px; background: white; animation-delay: 0.5s; }
  &.d5 { bottom: 40%; right: 25%; width: 28px; height: 28px; background: var(--pixel-cyan); border-width: 3px; animation-delay: 1.5s; }
}
@keyframes float {
